mapper.select:
SELECT g.*
FROM ts_role_image_generate_record g
         INNER JOIN ts_role_info r ON r.id = g.role_id
WHERE r.user_id = #{query.userId}
  AND (r.status IS NULL OR r.status != 0)

    AND (
        g.style_name LIKE CONCAT('%', #{query.keyword}, '%')
        OR g.request_id LIKE CONCAT('%', #{query.keyword}, '%')
        OR g.fail_reason LIKE CONCAT('%', #{query.keyword}, '%')
    )


    AND g.role_id = #{query.roleId}


    AND g.generate_status = #{query.generateStatus}


    AND g.apply_status = #{query.applyStatus}


    AND g.request_id = #{query.requestId}

ORDER BY g.updated_at DESC, g.id DESC
